int isValid(char *s) {
    char stack[1000];
    int top = -1;
    for (int i = 0; s[i]; i++) {
        if (s[i] == '(' || s[i] == '[' || s[i] == '{')
            stack[++top] = s[i];
        else {
            if (top == -1) return 0;
            char c = stack[top--];
            if (s[i] == ')' && c != '(') return 0;
            if (s[i] == ']' && c != '[') return 0;
            if (s[i] == '}' && c != '{') return 0;
        }
    }
    return top == -1;
}

